local FarmLeft  = Tabs.Farm:AddLeftGroupbox("ตั้งค่าฟาร์ม ")
local FarmRight = Tabs.Farm:AddRightGroupbox("สถานะ ")

local statusLabel = FarmRight:AddLabel({ Text = "สถานะ: ว่าง " })
local worldLabel  = FarmRight:AddLabel({ Text = "หอคอย: กำลังตรวจจับ... " })

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        if M.isSharedStallActive() then
            local remaining = math.max(0, math.ceil(M.getSharedStallUntil() - tick()))
            statusLabel:SetText("Status: Stalled " .. remaining .. "s ")
        elseif M.isClaimingWins() then
            statusLabel:SetText("สถานะ: กำลังรับชัยชนะ ")
        elseif M.isListening() then
            statusLabel:SetText("สถานะ: กำลังรอฟัง... ")
        elseif M.isAllCaptured() then
            statusLabel:SetText("สถานะ: พร้อมแล้ว! ")
        else
            statusLabel:SetText("สถานะ: ยังไม่ได้ตั้งค่า ")
        end
        worldLabel:SetText("Tower: " .. (M.getCurrentWorldName() or "not found") .. " ")
    end
end)

