local SpotLeft  = Tabs.Spot:AddLeftGroupbox("แทนที่ตำแหน่ง ")
local SpotRight = Tabs.Spot:AddRightGroupbox("ปุ่มบันทึกด่วน ")

local overrideLabel = SpotLeft:AddLabel({ Text = "ตำแหน่งกำหนดเอง: ปิด " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "บันทึกแล้ว: ไม่มี " })

SpotLeft:AddButton("บันทึกตำแหน่งปัจจุบัน ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="ข้อผิดพลาด ", Description="ไม่มีตัวละคร! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="ข้อผิดพลาด ", Description="ไม่มี HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="บันทึกตำแหน่งแล้ว! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("ล้างตำแหน่งกำหนดเอง ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("บันทึกแล้ว: ไม่มี ")
    Library:Notify({Title="ล้างแล้ว ", Description="ใช้จุดที่บันทึกเดิม ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

